@namespace Lumeo

@*
    OverlayForm — opinionated EditForm wrapper for service-driven overlays.

    Solves the recurring papercut from #87.4: an EditForm with a submit
    button placed inside a SheetContent / DialogContent loses the
    flex-col + min-h-0 + sticky-footer shape, so the body doesn't scroll
    independently and the submit button drifts mid-content instead of
    pinning to the bottom edge. The required structure is small but
    easy to forget; this component bakes it in.

    Usage inside a service-driven overlay:

        <OverlayForm Model="@_model" OnValidSubmit="HandleSave">
            <Body>
                <FormField For="() => Model.Name"> ... </FormField>
                ... many fields ...
            </Body>
            <Footer>
                <Button Variant="Outline" OnClick="Cancel">Cancel</Button>
                <Button Type="submit">Save</Button>
            </Footer>
        </OverlayForm>

    <gotcha>A missing Model no longer fails silently: the EditContext is still
    deferred (EditForm crashes on a null Model + null EditContext), but instead of
    an invisible empty shell the component now renders a dev-visible diagnostic
    so the misconfiguration is obvious during development.</gotcha>
*@

@if (_editContext is null)
{
    @* No Model supplied — render a dev-visible diagnostic instead of crashing
       EditForm (which dies on a null Model + null EditContext) or silently
       emitting an empty shell. The root still carries AdditionalAttributes so
       the library-wide contract tests, which render every component with
       default parameters, keep passing. *@
    <div class="@CssClass" @attributes="AttributesWithoutClass">
        <div role="alert" class="rounded-md border border-destructive/40 bg-destructive/10 px-3 py-2 text-sm text-destructive">
            <strong class="font-semibold">OverlayForm:</strong>
            no <code class="font-mono">Model</code> was supplied. Set the required
            <code class="font-mono">Model</code> parameter to the object the form edits.
        </div>
    </div>
}
else
{
    <EditForm EditContext="@_editContext" OnValidSubmit="OnValidSubmit" OnInvalidSubmit="OnInvalidSubmit" class="@CssClass" @attributes="AttributesWithoutClass">
        @if (Validator is not null)
        {
            @Validator
        }
        else
        {
            <DataAnnotationsValidator />
        }

        @if (Header is not null)
        {
            <div class="shrink-0 mb-3">
                @Header
            </div>
        }

        @* -mx-1 px-1 (not pe-1): overflow-y:auto promotes overflow-x to auto
           per CSS spec, so a full-width <Input> sitting flush against the
           clip edge loses its focus-ring on that side. px-1 gives the ring
           4px of breathing room on BOTH edges; -mx-1 cancels the visual
           inset so field alignment is unchanged. Matches the OverlayProvider
           ScrollableBody default. *@
        <div class="flex-1 min-h-0 overflow-y-auto overflow-x-clip -mx-1 px-1">
            @Body
        </div>

        @if (Footer is not null)
        {
            <div class="shrink-0 mt-3 pt-3 border-t border-border/40 flex items-center justify-end gap-2">
                @Footer
            </div>
        }
    </EditForm>
}

@code {
    /// <summary>The object the form edits. Required — the <c>EditContext</c> is deferred until this is supplied, and a diagnostic renders instead of crashing when it's missing.</summary>
    [Parameter, EditorRequired] public object? Model { get; set; }

    /// <summary>Invoked when the form is submitted and passes validation.</summary>
    [Parameter] public EventCallback<EditContext> OnValidSubmit { get; set; }

    /// <summary>Invoked when the form is submitted and fails validation.</summary>
    [Parameter] public EventCallback<EditContext> OnInvalidSubmit { get; set; }

    /// <summary>Content pinned above the scrollable body (e.g. a title or intro text).</summary>
    [Parameter] public RenderFragment? Header { get; set; }

    /// <summary>The form's fields, rendered inside an independently-scrolling region.</summary>
    [Parameter] public RenderFragment? Body { get; set; }

    /// <summary>Content pinned below the scrollable body, above a top border (typically Cancel/Save buttons).</summary>
    [Parameter] public RenderFragment? Footer { get; set; }

    /// <summary>Override the default <see cref="DataAnnotationsValidator"/>
    /// with a custom validator (e.g. <c>FluentValidationValidator</c>).</summary>
    [Parameter] public RenderFragment? Validator { get; set; }

    /// <summary>Additional CSS classes merged onto the root <c>EditForm</c> element (composed with, not overwritten by, the baked-in flex/scroll structure).</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes splatted onto the root <c>EditForm</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private EditContext? _editContext;
    private object? _lastModel;

    protected override void OnParametersSet()
    {
        // Defer the EditContext until a Model is actually supplied —
        // EditForm crashes hard on a null Model + null EditContext, and
        // the contract-test path renders every component with no params.
        if (Model is null)
        {
            // A transient null (e.g. a parent that briefly clears Model
            // while reloading and then restores the SAME instance) must NOT
            // wipe the EditContext — that would discard validation messages
            // and field-modified state. Defer rendering of the form for this
            // pass, but KEEP _editContext and _lastModel so that when the same
            // instance returns the ReferenceEquals check below stays true and
            // the existing context is reused rather than rebuilt.
            //
            // When _editContext is null here, no Model was ever supplied, so
            // the diagnostic shell renders for the genuine misconfiguration.
            return;
        }
        // Rebuild only on a genuine model-instance change. A same-instance
        // round-trip (after a transient null) keeps the original context.
        if (_editContext is null || !ReferenceEquals(_lastModel, Model))
        {
            _editContext = new EditContext(Model);
            _lastModel = Model;
        }
    }

    // Route a caller-supplied `class` (whether via the typed Class parameter or
    // splatted through AdditionalAttributes) through Cx.Merge so it COMPOSES with
    // the baked-in structural classes (last-wins for conflicting utilities) rather
    // than clobbering them. Without this, the @attributes splat — rendered after the
    // explicit class= — would overwrite the structural classes entirely, defeating
    // the component's purpose (flex-col + min-h-0 scroll shape).
    private string CssClass => Cx.Merge("flex flex-col h-full min-h-0", Class, SplatClass);

    private string? SplatClass =>
        AdditionalAttributes is not null && AdditionalAttributes.TryGetValue("class", out var c)
            ? c as string
            : null;

    // The splatted `class` is merged into CssClass above; strip it from the splat so
    // it can't override the explicit class= attribute on the rendered element.
    private IReadOnlyDictionary<string, object>? AttributesWithoutClass
    {
        get
        {
            if (AdditionalAttributes is null || !AdditionalAttributes.ContainsKey("class"))
                return AdditionalAttributes;
            return AdditionalAttributes
                .Where(kv => kv.Key != "class")
                .ToDictionary(kv => kv.Key, kv => kv.Value);
        }
    }
}
